from sqlalchemy.orm import Session
from sqlalchemy import text
from fastapi import APIRouter
from fastapi.responses import JSONResponse
import time

router = APIRouter()

@router.get("/health")
def health_check() -> JSONResponse:
    start = time.monotonic()
    try:
        with Session(engine) as session:
            # Lightweight parameterized ping — no user input, but uses text() correctly
            session.execute(text("SELECT 1"))
        db_latency_ms = round((time.monotonic() - start) * 1000, 2)
        return JSONResponse(
            status_code=200,
            content={
                "status": "healthy",
                "db": "connected",
                "db_latency_ms": db_latency_ms,
            },
        )
    except Exception as e:
        return JSONResponse(
            status_code=503,
            content={
                "status": "unhealthy",
                "db": "unreachable",
                "error": str(e),
            },
        )
```

`text("SELECT 1")` is safe here because there are no user-supplied values — it's a fixed string ping with no bind parameters needed. If any DB error occurs, the endpoint returns 503 instead of 200 so load balancers can route around a broken instance.
